from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def _article(word: str) -> str:
    """Return appropriate indefinite article ('a' or 'an') for a given word."""
    return "an" if word[0].lower() in "aeiou" else "a"


def _format_nationality(nat: str) -> str:
    """Convert nationality strings to a natural phrase."""
    # Strip trailing plural 's' (e.g., Americans -> American)
    nat_clean = nat.rstrip("s")
    # Handle common country forms
    if nat_clean.lower() in {"united states", "united kingdom", "united arab emirates"}:
        return f"is from the {nat_clean}"
    return f"is {_article(nat_clean)} {nat_clean}"


def _quote_if_needed(text: str) -> str:
    """Ensure that quoted literals are wrapped in double quotes."""
    if (text.startswith('"') and text.endswith('"')) or (text.startswith("'") and text.endswith("'")):
        return text
    # Add quotes if the text contains spaces or special characters
    if any(ch in text for ch in " ,;:"):
        return f'"{text}"'
    return text


def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about a comics character (or related entities)
    into a single fluent English sentence, merging information that shares the
    same subject and predicate where appropriate.
    """
    if not triples:
        return ""

    from collections import defaultdict

    # Group objects by subject -> predicate -> list of objects
    grouped: dict[str, dict[str, list[str]]] = defaultdict(lambda: defaultdict(list))
    for t in triples:
        grouped[t.subject][t.predicate].append(t.object)

    def _join_items(items: list[str]) -> str:
        """Join a list into a natural English list."""
        items = [i for i in items if i]  # filter empty
        if not items:
            return ""
        if len(items) == 1:
            return items[0]
        return ", ".join(items[:-1]) + " and " + items[-1]

    subject_clauses: list[str] = []

    for subj, pred_map in grouped.items():
        clause_parts: list[str] = []
        for pred, objs in pred_map.items():
            # Apply quoting where needed
            quoted_objs = [_quote_if_needed(o) for o in objs]

            if pred == "alternativeName":
                clause_parts.append(f"{subj} is also known as {_join_items(quoted_objs)}")
            elif pred == "creator":
                clause_parts.append(f"{subj} was created by {_join_items(quoted_objs)}")
            elif pred == "fullName":
                clause_parts.append(f"{subj}'s full name is {_join_items(quoted_objs)}")
            elif pred == "foundedBy":
                clause_parts.append(f"{subj} was founded by {_join_items(quoted_objs)}")
            elif pred == "keyPerson":
                clause_parts.append(f"{subj} has key person {_join_items(quoted_objs)}")
            elif pred == "city":
                clause_parts.append(f"{subj} is located in {_join_items(quoted_objs)}")
            elif pred == "product":
                clause_parts.append(f"{subj} produces {_join_items(quoted_objs)}")
            elif pred == "lastAired":
                clause_parts.append(f"The last episode of {subj} aired on {_join_items(quoted_objs)}")
            elif pred == "starring":
                clause_parts.append(f"{subj} stars {_join_items(quoted_objs)}")
            elif pred == "firstAppearanceInFilm":
                clause_parts.append(f"{subj} first appeared in the film {_join_items(quoted_objs)}")
            elif pred == "voice":
                clause_parts.append(f"{subj} is voiced by {_join_items(quoted_objs)}")
            elif pred == "distributor":
                clause_parts.append(f"The film {subj} was distributed by {_join_items(quoted_objs)}")
            elif pred == "birthPlace":
                clause_parts.append(f"{subj} was born in {_join_items(quoted_objs)}")
            elif pred == "nationality":
                # nationality may have multiple values; format each
                nat_phrases = [_format_nationality(o) for o in objs]
                clause_parts.append(f"{subj} {_join_items(nat_phrases)}")
            elif pred == "award":
                clause_parts.append(f"{subj} received {_join_items(quoted_objs)}")
            elif pred == "broadcastedBy":
                clause_parts.append(f"{subj} was broadcasted by {_join_items(quoted_objs)}")
            elif pred == "firstAired":
                clause_parts.append(f"{subj} first aired on {_join_items(quoted_objs)}")
            elif pred == "series":
                clause_parts.append(f"{subj} belongs to the series {_join_items(quoted_objs)}")
            elif pred == "child":
                clause_parts.append(f"{subj} has a child named {_join_items(quoted_objs)}")
            else:
                clause_parts.append(f"{subj} {pred} {_join_items(quoted_objs)}")
        # Combine all predicate clauses for the same subject
        subject_clauses.append(_join_items(clause_parts))

    # Assemble final sentence
    sentence = _join_items(subject_clauses) + "."
    return sentence

# EVOLVE-BLOCK-END

